        distance_to_non_hs = calculate_distance_ly(border_hs_system, border_non_hs_system)
        if distance_to_non_hs > self.max_range:
            continue

        # Check if we can reach the destination from the non-HS system
        distance_to_dest = calculate_distance_ly(border_non_hs_system, end_system)
        if distance_to_dest > self.max_range * 2:  # Rough heuristic
            continue

