            if gate_path:
                route.gate_jumps = gate_path + route.gate_jumps

            # Add the initial jump from border HS to non-HS
            # We need to create a leg for the first jump
            first_leg = JumpLeg(
                from_system=border_hs_system.name,
                to_system=border_non_hs_system.name,
                distance_ly=distance_to_non_hs,
                station_name=border_station.name,
                isotopes_used=calculate_isotopes(distance_to_non_hs, self.base_fuel),
                fatigue_after=0,
                cooldown_after=0
            )
            route.legs.insert(0, first_leg)
            route.total_isotopes += first_leg.isotopes_used
